pub fn rrf_merge(
    vector_results: &[(String, f32)],
    bm25_results: &[(String, f32)],
    ppr_results: &[(String, f32)],
    vector_weight: f32,
    bm25_weight: f32,
    ppr_weight: f32,
    limit: usize,
) -> Vec<(String, RrfScores)> {
    let mut scores: HashMap<String, RrfScores> = HashMap::new();

    for (rank, (id, original_score)) in vector_results.iter().enumerate() {
        let rrf_score = vector_weight / (RRF_K + rank as f32 + 1.0);
        let entry = scores.entry(id.clone()).or_default();
        entry.vector_score = *original_score;
        entry.combined_score += rrf_score;
    }

    for (rank, (id, original_score)) in bm25_results.iter().enumerate() {
        let rrf_score = bm25_weight / (RRF_K + rank as f32 + 1.0);
        let entry = scores.entry(id.clone()).or_default();
        entry.bm25_score = *original_score;
        entry.combined_score += rrf_score;
    }

    for (rank, (id, original_score)) in ppr_results.iter().enumerate() {
        let rrf_score = ppr_weight / (RRF_K + rank as f32 + 1.0);
        let entry = scores.entry(id.clone()).or_default();
        entry.ppr_score = *original_score;
        entry.combined_score += rrf_score;
    }

    let mut results: Vec<_> = scores.into_iter().collect();
    results.sort_by(|a, b| {
        b.1.combined_score
            .partial_cmp(&a.1.combined_score)
            .unwrap_or(std::cmp::Ordering::Equal)
    });
    results.truncate(limit);
    results
}

async fn test_indexer_batching() {
        let ctx = TestContext::new().await;
        let project_dir = ctx._temp_dir.path().join("test_project");
        fs::create_dir_all(&project_dir).unwrap();

        for i in 0..150 {
            let file_path = project_dir.join(format!("file_{}.rs", i));
            fs::write(file_path, format!("fn test_{}() {{}}", i)).unwrap();
        }

        // Must run with a real queue/worker setup or mock state
        // For unit test, we can just use the ctx.state which has a dummy queue if we updated TestContext
        // But TestContext::new() needs to be updated to initialize embedding_queue.

        let status = index_project(ctx.state.clone(), &project_dir)
            .await
            .unwrap();

        assert_eq!(status.total_files, 150);
        assert_eq!(status.total_chunks, 150);

        // Use in-memory BM25 engine (rebuilt automatically after indexing)
        let chunks = ctx
            .state
            .code_search
            .search("fn test", None, 200, ctx.state.storage.as_ref())
            .await;
        assert_eq!(chunks.len(), 150);
    }

