    let phases = captured_phases.lock().unwrap().clone();
    for required_phase in [
        "cleanup",
        "scan",
        "file_read_hash",
        "parse_chunk",
        "chunk_db_write",
        "symbol_db_write",
        "embedding_enqueue",
        "status_update",
        "bm25_rebuild",
        "total_index",
    ] {
        eprintln!("captured_timing_phase={required_phase}");
