                })?;
                Some(
                    self.search_symbols_with_session(Parameters(params), session_context)
                        .await,
                )
            }
            _ => None,
        };

        if let Some(result) = direct_result {
            return result;
        }

        let tool_context = ToolCallContext::new(self, request, context);
        self.tool_router.call(tool_context).await
    }
