async fn stdio_no_session_binding_unsupported() {
    let ctx = TestContext::new().await;
    let server = MemoryMcpServer::new(ctx.state.clone());

    let bind = server
        .project_info_with_session(
            Parameters(ProjectInfoParams {
                action: "bind".to_string(),
